#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; long long A,B; scanf("%d %lld %lld",&N,&A,&B);
        long long sScore=0, aScore=0; char s[105];
        for(int i=0;i<N;i++){
            scanf("%s",s);
            char c=s[0];
            if(c=='E'||c=='Q'||c=='U'||c=='I'||c=='N'||c=='O'||c=='X') sScore+=A;
            else aScore+=B;
        }
        if(sScore>aScore) printf("SARTHAK\n");
        else if(aScore>sScore) printf("ANURADHA\n");
        else printf("DRAW\n");
    }
    return 0;
}

