import sys

def solve():
    data=sys.stdin.read().strip().splitlines()
    if not data: return
    it=iter(data)
    T=int(next(it))
    good=set('EQUINOX')
    out=[]
    for _ in range(T):
        N,A,B=map(int,next(it).split())
        sScore=aScore=0
        for _ in range(N):
            s=next(it).strip()
            if s and s[0] in good:
                sScore+=A
            else:
                aScore+=B
        if sScore>aScore:
            out.append('SARTHAK')
        elif aScore>sScore:
            out.append('ANURADHA')
        else:
            out.append('DRAW')
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    solve()

